('browser-compatibility', 'grp-browser-compatibility', 1, 'topic', NULL, NULL, NULL, 'Browser Compatibility', 'Use compatibility tables, feature detection, polyfills, Baseline awareness, and graceful fallbacks.', 'choice', 3, 'intermediate', '{"source": "roadmap.sh/frontend", "nodeKey": "browser-compatibility"}'::jsonb, true, true, '["Explain how Browser Compatibility affects practical frontend engineering work.", "Apply Browser Compatibility to implement user-facing interfaces or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Browser Compatibility in context.", "Use the concept to build or review a small UI behavior.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('progressive-enhancement', 'grp-browser-compatibility', 2, 'topic', NULL, NULL, NULL, 'Progressive Enhancement', 'Start with semantic HTML and layer CSS/JavaScript behavior so core experiences remain usable.', 'choice', 3, 'intermediate', '{"source": "roadmap.sh/frontend", "nodeKey": "progressive-enhancement"}'::jsonb, true, true, '["Explain how Progressive Enhancement affects practical frontend engineering work.", "Apply Progressive Enhancement to implement user-facing interfaces or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Progressive Enhancement in context.", "Use the concept to produce a small applied example or decision note.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('responsive-images-fonts', 'grp-browser-compatibility', 3, 'topic', NULL, NULL, NULL, 'Responsive Images and Fonts', 'Use srcset, sizes, modern image formats, lazy loading, font-display, preloading, and layout-shift prevention.', 'choice', 4, 'intermediate', '{"source": "roadmap.sh/frontend", "nodeKey": "responsive-images-fonts"}'::jsonb, true, true, '["Explain how Responsive Images and Fonts affects practical frontend engineering work.", "Apply Responsive Images and Fonts to implement user-facing interfaces or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Responsive Images and Fonts in context.", "Use the concept to produce a small applied example or decision note.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('proj-component-library', 'ph-ui-quality', 91, 'project', NULL, NULL, NULL, 'Optional Component Library Slice', 'Optional practice project: Build a small documented component library with tokens, reusable components, accessibility notes, and visual states.', 'side', 7, 'intermediate', '{"whatToBuild":"Build a small documented component library with tokens, reusable components, accessibility notes, and visual states.","buildSteps":["Define the Component Library Slice scenario and list the specific items to demonstrate: accessibility checks.","Sketch the core screen, state changes, empty/loading/error states, and accessibility expectations.","Implement the main UI flow with realistic sample data or API integration.","Add validation, responsive behavior, and feedback for at least one failure or edge case.","Capture screenshots or a short walkthrough showing the intended user path.","Document how to run or review the Component Library Slice deliverable, including inputs, expected outputs, and known limitations."],"source":"roadmap.sh/frontend","nodeKey":"proj-component-library"}'::jsonb, false, true, '["Apply Frontend Project Work through a focused Component Library Slice artifact.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The a reviewable Component Library Slice interface or component flow with screenshots and interaction notes is available for review.","The Component Library Slice scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness."]'::jsonb),
('ph-frontend-portfolio', NULL, 16, 'phase', NULL, NULL, NULL, 'Frontend Portfolio and Interview Readiness', 'Package frontend work into credible proof: deployed apps, docs, tests, metrics, and architecture explanations.', 'trunk', NULL, NULL, '{"source": "roadmap.sh/frontend", "nodeKey": "ph-frontend-portfolio"}'::jsonb, true, false, '["Frontend Portfolio and Interview Readiness"]'::jsonb, '["Required child topics are completed"]'::jsonb),
('grp-portfolio-evidence', 'ph-frontend-portfolio', 1, 'choice_group', NULL, 'complete_all', NULL, 'Portfolio Evidence', 'Make finished frontend work easy to review.', 'side', NULL, NULL, '{"progressRule": "complete_all", "source": "roadmap.sh/frontend", "nodeKey": "grp-portfolio-evidence"}'::jsonb, true, false, '["Portfolio Evidence"]'::jsonb, '["Required child topics are completed"]'::jsonb),
('frontend-readme-docs', 'grp-portfolio-evidence', 1, 'topic', NULL, NULL, NULL, 'Frontend README and Setup Docs', 'Write clear setup, env var, script, test, deployment, architecture, and known-limitations documentation.', 'choice', 2, 'beginner', '{"source": "roadmap.sh/frontend", "nodeKey": "frontend-readme-docs"}'::jsonb, true, true, '["Explain how Frontend README and Setup Docs affects practical frontend engineering work.", "Apply Frontend README and Setup Docs to implement user-facing interfaces or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Frontend README and Setup Docs in context.", "Use the concept to build or review a small UI behavior.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('frontend-architecture-notes', 'grp-portfolio-evidence', 2, 'topic', NULL, NULL, NULL, 'Frontend Architecture Notes', 'Explain component structure, state choices, API boundaries, routing, auth, testing, and performance decisions.', 'choice', 3, 'intermediate', '{"source": "roadmap.sh/frontend", "nodeKey": "frontend-architecture-notes"}'::jsonb, true, true, '["Explain how Frontend Architecture Notes affects practical frontend engineering work.", "Apply Frontend Architecture Notes to implement user-facing interfaces or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Frontend Architecture Notes in context.", "Use the concept to build or review a small UI behavior.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('portfolio-polish', 'grp-portfolio-evidence', 3, 'topic', NULL, NULL, NULL, 'Portfolio Polish', 'Improve visual consistency, mobile behavior, accessibility, metadata, screenshots, demo data, and deployed reliability.', 'choice', 4, 'intermediate', '{"source": "roadmap.sh/frontend", "nodeKey": "portfolio-polish"}'::jsonb, true, true, '["Explain how Portfolio Polish affects practical frontend engineering work.", "Apply Portfolio Polish to implement user-facing interfaces or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Portfolio Polish in context.", "Use the concept to produce a small applied example or decision note.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('grp-interview-readiness', 'ph-frontend-portfolio', 2, 'choice_group', NULL, 'complete_all', NULL, 'Frontend Interview Readiness', 'Prepare to explain frontend decisions clearly.', 'side', NULL, NULL, '{"progressRule": "complete_all", "source": "roadmap.sh/frontend", "nodeKey": "grp-interview-readiness"}'::jsonb, true, false, '["Frontend Interview Readiness"]'::jsonb, '["Required child topics are completed"]'::jsonb),
('frontend-debugging-stories', 'grp-interview-readiness', 1, 'topic', NULL, NULL, NULL, 'Debugging Stories', 'Practice explaining real bugs involving CORS, layout, state, async requests, auth, performance, and deployment.', 'choice', 3, 'intermediate', '{"source": "roadmap.sh/frontend", "nodeKey": "frontend-debugging-stories"}'::jsonb, true, true, '["Explain how Debugging Stories affects practical frontend engineering work.", "Apply Debugging Stories to implement user-facing interfaces or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Debugging Stories in context.", "Use the concept to produce a small applied example or decision note.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('frontend-code-review', 'grp-interview-readiness', 2, 'topic', NULL, NULL, NULL, 'Frontend Code Review', 'Review UI code for accessibility, state bugs, component boundaries, naming, testability, and performance risks.', 'choice', 3, 'intermediate', '{"source": "roadmap.sh/frontend", "nodeKey": "frontend-code-review"}'::jsonb, true, true, '["Explain how Frontend Code Review affects practical frontend engineering work.", "Apply Frontend Code Review to implement user-facing interfaces or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Frontend Code Review in context.", "Use the concept to build or review a small UI behavior.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('frontend-system-design-basics', 'grp-interview-readiness', 3, 'topic', NULL, NULL, NULL, 'Frontend System Design Basics', 'Discuss rendering, routing, state, caching, API contracts, performance budgets, design systems, and deployment strategy.', 'choice', 5, 'advanced', '{"source": "roadmap.sh/frontend", "nodeKey": "frontend-system-design-basics"}'::jsonb, true, true, '["Explain how Frontend System Design Basics affects practical frontend engineering work.", "Apply Frontend System Design Basics to implement user-facing interfaces or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Frontend System Design Basics in context.", "Use the concept to build or review a small UI behavior.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('gate-portfolio-review', 'ph-frontend-portfolio', 81, 'checkpoint', 'assessment', NULL, NULL, 'Portfolio Review Gate', 'Final roadmap checkpoint for Frontend Portfolio and Interview Readiness. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the frontend engineering path.', 'checkpoint', 2, 'intermediate', '{"reviewFocus":"Final roadmap checkpoint for Frontend Portfolio and Interview Readiness. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the frontend engineering path.","reviewCriteria":["Summarize completed phases, projects, and major skill groups.","Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.","List remaining gaps or specialization topics for future learning.","State that the checkpoint is a planning review, not proof of job readiness."],"source":"roadmap.sh/frontend","nodeKey":"gate-portfolio-review"}'::jsonb, true, true, '["Connect completed roadmap work to a coherent frontend engineering learning narrative.", "Review portfolio or project evidence and identify which artifacts are ready to share.", "Define remaining gaps and future specialization priorities."]'::jsonb, '["Summarize completed phases, projects, and major skill groups.", "Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.", "List remaining gaps or specialization topics for future learning.", "State that the checkpoint is a planning review, not proof of job readiness."]'::jsonb),
('proj-portfolio-final-package', 'ph-frontend-portfolio', 91, 'project', NULL, NULL, NULL, 'Required Portfolio Final Package', 'Capstone project: Polish the capstone with README, architecture notes, screenshots, deploy link, test instructions, performance results, and known tradeoffs.', 'checkpoint', 8, 'intermediate', '{"whatToBuild":"Polish the capstone with README, architecture notes, screenshots, deploy link, test instructions, performance results, and known tradeoffs.","buildSteps":["Define the Portfolio Final Package scenario and list the specific items to demonstrate: test evidence.","Choose a coherent product or case-study scenario that can integrate the strongest projects from the roadmap.","Define the architecture, data or workflow model, user path, and review evidence before implementation.","Build the core artifact end-to-end with scoped features rather than disconnected demos.","Add validation evidence appropriate to the role, such as tests, metrics, query checks, playtest notes, traces, screenshots, or incident notes.","Prepare a case study explaining decisions, trade-offs, limitations, and what would need further review for real deployment.","Package the repository or artifact so another person can reproduce or inspect the result.","Create a review checklist that connects the artifact to the relevant skills and roadmap segment.","Write a limitation and risk section so the project is presented as reviewable evidence, not a certification claim."],"source":"roadmap.sh/frontend","nodeKey":"proj-portfolio-final-package"}'::jsonb, true, true, '["Apply Frontend Project Work, React, JavaScript through a focused Portfolio Final Package artifact.","Integrate multiple roadmap areas into one coherent case study rather than isolated exercises.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The a portfolio-ready Portfolio Final Package case study and integrated artifact is available for review.","The Portfolio Final Package scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","The case study connects implementation decisions to relevant roadmap skills and explains why alternatives were not chosen.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness.","The project is packaged so a reviewer can understand the artifact without live mentoring."]'::jsonb);
